// FACIS Feeds & Envelope Assembly — orchestration
// Math is duplicated from subflows/*-simulator.subflow.json — keep in sync.

const ENERGY_TOPIC_KEYS = ['meters', 'pv', 'weather', 'price', 'consumers'];

function makeRng(baseSeed, entityId, tag, tsMs) {
    const key = String(baseSeed) + ':' + String(entityId) + ':' + String(tag) + ':' + String(tsMs);
    const seedHex = crypto.createHash('sha256').update(key).digest('hex').slice(0, 16);
    return seedrandom.alea(seedHex);
}
const uniform = (rng, a, b) => a + (b - a) * rng();
function normal(rng, mean, stddev) {
    let u = 0; let v = 0;
    while (u === 0) u = rng();
    while (v === 0) v = rng();
    const z = Math.sqrt(-2 * Math.log(u)) * Math.cos(2 * Math.PI * v);
    return mean + stddev * z;
}
const isWeekendDate = (d) => { const w = d.getUTCDay(); return w === 0 || w === 6; };
function dayOfYear(d) {
    const start = Date.UTC(d.getUTCFullYear(), 0, 0);
    return Math.floor((d.getTime() - start) / 86400000);
}

// --- Weather ---
function weather(payload) {
    const d = new Date(payload.timestamp);
    const cfg = Object.assign({
        latitude: 52.52, longitude: 13.405,
        base_temperature_summer_c: 22, base_temperature_winter_c: 0,
        daily_temp_amplitude_c: 8, temperature_variance_c: 1.5,
        base_humidity_percent: 65, humidity_variance_percent: 8,
        base_wind_speed_ms: 4.0, wind_variance_ms: 1.5,
        prevailing_wind_direction_deg: 270, wind_direction_variance_deg: 30,
        base_cloud_cover_percent: 40, cloud_variance_percent: 15,
        max_clear_sky_ghi_w_m2: 1000
    }, payload.config || {});
    const tsMs = payload.timestamp_ms;
    const cloudRng = makeRng(payload.base_seed, payload.entity_id, 'cloud', tsMs);
    const tempRng = makeRng(payload.base_seed, payload.entity_id, 'temp', tsMs);
    const humRng = makeRng(payload.base_seed, payload.entity_id, 'hum', tsMs);
    const windSRng = makeRng(payload.base_seed, payload.entity_id, 'winds', tsMs);
    const windDRng = makeRng(payload.base_seed, payload.entity_id, 'windd', tsMs);
    const irrRng = makeRng(payload.base_seed, payload.entity_id, 'irr', tsMs);

    const seas = Math.cos(2 * Math.PI * (dayOfYear(d) - 182) / 365);
    const hour = d.getUTCHours() + d.getUTCMinutes() / 60;
    const diurnal = Math.cos(2 * Math.PI * (hour - 15) / 24);
    const seasMid = (cfg.base_temperature_summer_c + cfg.base_temperature_winter_c) / 2;
    const seasAmp = (cfg.base_temperature_summer_c - cfg.base_temperature_winter_c) / 2;
    const eff = cfg.daily_temp_amplitude_c * (0.6 + 0.4 * (seas + 1) / 2);
    let temp = seasMid + seasAmp * seas + eff * diurnal;
    if (cfg.temperature_variance_c > 0) temp += normal(tempRng, 0, cfg.temperature_variance_c);

    let hum = cfg.base_humidity_percent - Math.max(0, temp - 15);
    if (cfg.humidity_variance_percent > 0) hum += normal(humRng, 0, cfg.humidity_variance_percent);
    hum = Math.max(20, Math.min(95, hum));

    const dwf = Math.max(0.6, Math.min(1.4, 1 - 0.4 * Math.cos(2 * Math.PI * (hour - 14) / 24)));
    let ws = cfg.base_wind_speed_ms * dwf;
    if (cfg.wind_variance_ms > 0) ws += normal(windSRng, 0, cfg.wind_variance_ms);
    ws = Math.max(0, ws);

    let wd = cfg.prevailing_wind_direction_deg;
    if (cfg.wind_direction_variance_deg > 0) wd += normal(windDRng, 0, cfg.wind_direction_variance_deg);
    wd = ((wd % 360) + 360) % 360;

    let cover = cfg.base_cloud_cover_percent * (1 - 0.15 * Math.cos(2 * Math.PI * (hour - 15) / 24));
    if (cfg.cloud_variance_percent > 0) cover += normal(cloudRng, 0, cfg.cloud_variance_percent);
    cover = Math.max(0, Math.min(100, cover));

    const decl = (23.45 * Math.PI / 180) * Math.sin(2 * Math.PI * (284 + dayOfYear(d)) / 365);
    const b = 2 * Math.PI * (dayOfYear(d) - 81) / 365;
    const eot = 9.87 * Math.sin(2 * b) - 7.53 * Math.cos(b) - 1.5 * Math.sin(b);
    const solarTime = (d.getUTCHours() + d.getUTCMinutes() / 60 + d.getUTCSeconds() / 3600) * 60 + 4 * cfg.longitude + eot;
    const haDeg = (solarTime / 4) - 180;
    const ha = haDeg * Math.PI / 180;
    const lat = cfg.latitude * Math.PI / 180;
    const sinAlt = Math.sin(lat) * Math.sin(decl) + Math.cos(lat) * Math.cos(decl) * Math.cos(ha);
    const altR = Math.asin(Math.max(-1, Math.min(1, sinAlt)));
    const altDeg = Math.max(0, altR * 180 / Math.PI);

    let irradiance = { ghi_w_m2: 0, dni_w_m2: 0, dhi_w_m2: 0 };
    if (altDeg > 0) {
        const am = 1 / Math.max(Math.sin(altR), 0.05);
        const trans = Math.pow(0.7, Math.pow(am, 0.678));
        const clearSky = Math.max(0, cfg.max_clear_sky_ghi_w_m2 * Math.sin(altR) * trans);
        let f = 1 - 0.5 * (cover / 100);
        f = Math.max(0.3, Math.min(1, f + uniform(irrRng, -0.05, 0.05)));
        const ghi = clearSky * f;
        const kt = 1 - 0.7 * (cover / 100);
        let df;
        if (kt <= 0.22) df = 1 - 0.09 * kt;
        else if (kt <= 0.8) df = 0.9511 - 0.1604 * kt + 4.388 * kt * kt - 16.638 * Math.pow(kt, 3) + 12.336 * Math.pow(kt, 4);
        else df = 0.165;
        const dhi = ghi * df;
        const dh = ghi - dhi;
        const dni = dh / Math.max(Math.sin(altR), 0.05);
        irradiance = {
            ghi_w_m2: Math.max(0, ghi),
            dni_w_m2: Math.max(0, Math.min(dni, 1200)),
            dhi_w_m2: Math.max(0, dhi)
        };
    }

    return {
        site_id: payload.site_id || '',
        timestamp: payload.timestamp,
        location: { latitude: cfg.latitude, longitude: cfg.longitude },
        conditions: {
            temperature_c: temp, humidity_percent: hum,
            wind_speed_ms: ws, wind_direction_deg: wd,
            cloud_cover_percent: cover,
            ghi_w_m2: irradiance.ghi_w_m2,
            dni_w_m2: irradiance.dni_w_m2,
            dhi_w_m2: irradiance.dhi_w_m2
        }
    };
}

// --- PV (uses weather output) ---
function pv(payload, weatherReading) {
    const cfg = Object.assign({
        nominal_capacity_kwp: 10, noct_c: 45,
        temperature_coefficient_pct_per_c: -0.4,
        reference_temperature_c: 25, system_losses_percent: 14,
        interval_minutes: 15
    }, payload.config || {});
    const ghi = (weatherReading && weatherReading.conditions) ? weatherReading.conditions.ghi_w_m2 : 0;
    const ambient = (weatherReading && weatherReading.conditions) ? weatherReading.conditions.temperature_c : 15;
    const modT = ghi <= 0 ? ambient : ambient + (cfg.noct_c - 20) * (ghi / 800);
    let derating = 1 + (cfg.temperature_coefficient_pct_per_c / 100) * (modT - cfg.reference_temperature_c);
    derating = Math.max(0, Math.min(1.2, derating));
    let power = ghi <= 0 ? 0 : cfg.nominal_capacity_kwp * (ghi / 1000) * derating * (1 - cfg.system_losses_percent / 100);
    power = Math.min(power, cfg.nominal_capacity_kwp);
    const efficiency = (ghi <= 0 || power <= 0) ? 0 : Math.min(100, (power / (cfg.nominal_capacity_kwp * (ghi / 1000))) * 100);

    // Daily energy state in flow context
    const dateKey = payload.timestamp.slice(0, 10);
    const all = flow.get('pv_daily') || {};
    const st = all[payload.entity_id] || { date: dateKey, kwh: 0 };
    if (st.date !== dateKey) { st.date = dateKey; st.kwh = 0; }
    st.kwh += power * ((cfg.interval_minutes || 15) / 60);
    all[payload.entity_id] = st;
    flow.set('pv_daily', all);

    return {
        site_id: payload.site_id || '',
        system_id: payload.entity_id,
        timestamp: payload.timestamp,
        readings: {
            power_output_kw: power, daily_energy_kwh: st.kwh,
            irradiance_w_m2: ghi, module_temperature_c: modT,
            efficiency_percent: efficiency
        }
    };
}

// --- Meter ---
const WEEKDAY_LF = [0.30,0.28,0.25,0.25,0.27,0.35,0.55,0.75,0.90,0.95,1.00,0.98,0.85,0.92,0.98,0.95,0.88,0.70,0.50,0.45,0.40,0.38,0.35,0.32];
const WEEKEND_LF = [0.20,0.18,0.16,0.15,0.15,0.18,0.25,0.35,0.45,0.50,0.55,0.52,0.45,0.48,0.50,0.48,0.42,0.35,0.30,0.28,0.25,0.23,0.22,0.21];
function meter(payload) {
    const cfg = Object.assign({
        base_power_kw: 10, peak_power_kw: 50, nominal_voltage_v: 230,
        voltage_variance_pct: 5, nominal_frequency_hz: 50, frequency_variance_hz: 0.05,
        power_factor_min: 0.95, power_factor_max: 0.99, initial_energy_kwh: 0
    }, payload.config || {});
    const d = new Date(payload.timestamp);
    const tsMs = payload.timestamp_ms;
    const rng = makeRng(payload.base_seed, payload.entity_id, 'meter', tsMs);
    const curve = isWeekendDate(d) ? WEEKEND_LF : WEEKDAY_LF;
    const h = d.getUTCHours(); const m = d.getUTCMinutes();
    const cur = curve[h]; const nxt = curve[(h + 1) % 24];
    let lf = cur + (nxt - cur) * (m / 60);
    lf = Math.max(0.1, Math.min(1, lf + normal(rng, 0, 0.05)));
    let totalKw = cfg.base_power_kw + (cfg.peak_power_kw - cfg.base_power_kw) * lf;
    if (payload.mode === 'event') {
        const minOfDay = h * 60 + m;
        if (minOfDay >= 600 && minOfDay < 620) totalKw *= 2;
    }
    const totalW = totalKw * 1000;
    const share = totalW / 3;
    const i1off = uniform(rng, -0.08, 0.08);
    const i2off = uniform(rng, -0.08, 0.08);
    const i3off = -(i1off + i2off);
    const p1 = share * (1 + i1off); const p2 = share * (1 + i2off); const p3 = share * (1 + i3off);
    const vVar = cfg.nominal_voltage_v * cfg.voltage_variance_pct / 100;
    const v1 = cfg.nominal_voltage_v + uniform(rng, -vVar, vVar);
    const v2 = cfg.nominal_voltage_v + uniform(rng, -vVar, vVar);
    const v3 = cfg.nominal_voltage_v + uniform(rng, -vVar, vVar);
    const pf = uniform(rng, cfg.power_factor_min, cfg.power_factor_max);
    const i1 = v1 > 0 ? p1 / (v1 * pf) : 0;
    const i2 = v2 > 0 ? p2 / (v2 * pf) : 0;
    const i3 = v3 > 0 ? p3 / (v3 * pf) : 0;
    const freq = cfg.nominal_frequency_hz + uniform(rng, -cfg.frequency_variance_hz, cfg.frequency_variance_hz);
    const ref = Date.UTC(d.getUTCFullYear(), 0, 1, 0, 0, 0);
    let energy = cfg.initial_energy_kwh;
    if (d.getTime() > ref) {
        const totalH = (d.getTime() - ref) / 3600000;
        const avg = cfg.base_power_kw + (cfg.peak_power_kw - cfg.base_power_kw) * 0.53;
        energy = cfg.initial_energy_kwh + avg * totalH;
    }
    return {
        site_id: payload.site_id || '',
        timestamp: payload.timestamp,
        meter_id: payload.entity_id,
        readings: {
            active_power_l1_w: p1, active_power_l2_w: p2, active_power_l3_w: p3,
            voltage_l1_v: v1, voltage_l2_v: v2, voltage_l3_v: v3,
            current_l1_a: i1, current_l2_a: i2, current_l3_a: i3,
            power_factor: pf, frequency_hz: freq, total_energy_kwh: energy
        }
    };
}

// --- Price ---
const PRICE_MULT = [0.90,0.85,0.82,0.83,0.88,0.95,1.05,1.15,1.25,1.10,1.05,1.00,0.98,0.95,0.97,1.02,1.08,1.20,1.35,1.40,1.15,1.05,0.98,0.93];
function price(payload) {
    const cfg = Object.assign({
        night_price: 0.08, morning_peak_price: 0.18, midday_price: 0.12,
        evening_peak_price: 0.22, evening_price: 0.14,
        weekend_discount_pct: 7.5, volatility_pct: 8, min_price: 0.01
    }, payload.config || {});
    const d = new Date(payload.timestamp);
    const rng = makeRng(payload.base_seed, payload.entity_id, 'price', payload.timestamp_ms);
    const h = d.getUTCHours();
    const m = d.getUTCMinutes();
    const tariff = h < 6 ? 'NIGHT' : h < 9 ? 'MORNING_PEAK' : h < 17 ? 'MIDDAY' : h < 20 ? 'EVENING_PEAK' : 'EVENING';
    const base = ({ NIGHT: cfg.night_price, MORNING_PEAK: cfg.morning_peak_price, MIDDAY: cfg.midday_price, EVENING_PEAK: cfg.evening_peak_price, EVENING: cfg.evening_price })[tariff];
    const mult = PRICE_MULT[h] + (PRICE_MULT[(h + 1) % 24] - PRICE_MULT[h]) * (m / 60);
    let p = base * mult;
    if (isWeekendDate(d)) p *= (1 - cfg.weekend_discount_pct / 100);
    let vol = cfg.volatility_pct;
    if (payload.mode === 'event') vol *= 2;
    p *= (1 + normal(rng, 0, vol / 100));
    p = Math.max(p, cfg.min_price);
    return {
        timestamp: payload.timestamp,
        feed_id: payload.entity_id,
        price_eur_per_kwh: p,
        tariff_type: tariff
    };
}

// --- Consumer ---
function consumer(payload) {
    const cfg = Object.assign({
        device_type: 'industrial_oven', rated_power_kw: 3, duty_cycle_pct: 70,
        power_variance_pct: 5, operate_on_weekends: false,
        operating_windows: [{ start_hour: 6, end_hour: 18 }]
    }, payload.config || {});
    const d = new Date(payload.timestamp);
    const rng = makeRng(payload.base_seed, payload.entity_id, 'consumer', payload.timestamp_ms);
    let canOperate = true;
    if (isWeekendDate(d) && !cfg.operate_on_weekends) canOperate = false;
    if (canOperate) {
        const h = d.getUTCHours();
        let inAny = false;
        for (const w of cfg.operating_windows) {
            if (w.start_hour <= w.end_hour) { if (h >= w.start_hour && h < w.end_hour) { inAny = true; break; } }
            else if (h >= w.start_hour || h < w.end_hour) { inAny = true; break; }
        }
        canOperate = inAny;
    }
    let state = 'OFF';
    if (canOperate && rng() < cfg.duty_cycle_pct / 100) state = 'ON';
    if (payload.mode === 'event') {
        const minOfDay = d.getUTCHours() * 60 + d.getUTCMinutes();
        if (minOfDay >= 1020 && minOfDay < 1140) state = 'ON';
    }
    let power = 0;
    if (state === 'ON') {
        const v = cfg.rated_power_kw * cfg.power_variance_pct / 100;
        power = Math.max(0, cfg.rated_power_kw + uniform(rng, -v, v));
    }
    return {
        site_id: payload.site_id || '',
        timestamp: payload.timestamp,
        device_id: payload.entity_id,
        device_type: cfg.device_type,
        device_state: state,
        device_power_kw: power
    };
}

// --- City event ---
function cityEvent(payload) {
    if ((payload.mode || 'normal') !== 'event') {
        return {
            city_id: payload.city_id || 'city-berlin',
            zone_id: payload.zone_id || 'zone-001',
            timestamp: payload.timestamp,
            event_type: 'EVENT', severity: 'LOW', severity_num: 1, active: false
        };
    }
    const d = new Date(payload.timestamp);
    const epoch = Date.UTC(1, 0, 1);
    const dayOrd = Math.floor((Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()) - epoch) / 86400000) + 1;
    const rng = makeRng(payload.base_seed, payload.entity_id, 'event-day', dayOrd);
    const schedule = [
        { hour: 9, duration: 30, type: 'ACCIDENT', severity: 'MEDIUM', severity_num: 2 },
        { hour: 14, duration: 45, type: 'EMERGENCY', severity: 'HIGH', severity_num: 3 },
        { hour: 20, duration: 20, type: 'EVENT', severity: 'LOW', severity_num: 1 }
    ].map(e => ({ ...e, hour: Math.max(0, Math.min(23, e.hour + Math.floor(uniform(rng, -1, 2)))) }));
    const minOfDay = d.getUTCHours() * 60 + d.getUTCMinutes();
    for (const e of schedule) {
        if (minOfDay >= e.hour * 60 && minOfDay < e.hour * 60 + e.duration) {
            return {
                city_id: payload.city_id || 'city-berlin',
                zone_id: payload.zone_id || 'zone-001',
                timestamp: payload.timestamp,
                event_type: e.type, severity: e.severity, severity_num: e.severity_num,
                active: true
            };
        }
    }
    return {
        city_id: payload.city_id || 'city-berlin',
        zone_id: payload.zone_id || 'zone-001',
        timestamp: payload.timestamp,
        event_type: 'EVENT', severity: 'LOW', severity_num: 1, active: false
    };
}

// --- Streetlight ---
function calcSunHours(date, latitude, longitude) {
    const decl = 23.45 * Math.sin((Math.PI / 180) * (360 / 365) * (dayOfYear(date) - 81));
    const declRad = decl * Math.PI / 180;
    const latRad = latitude * Math.PI / 180;
    let cosHa = -Math.tan(latRad) * Math.tan(declRad);
    cosHa = Math.max(-1, Math.min(1, cosHa));
    const haDeg = Math.acos(cosHa) * 180 / Math.PI;
    const noonH = 12 - longitude / 15;
    return [Math.max(0, Math.min(23.99, noonH - haDeg / 15)), Math.max(0, Math.min(23.99, noonH + haDeg / 15))];
}
function streetlight(payload, activeEvent) {
    const cfg = Object.assign({ rated_power_w: 100, latitude: 52.52, longitude: 13.405 }, payload.config || {});
    const d = new Date(payload.timestamp);
    const rng = makeRng(payload.base_seed, payload.entity_id, 'light', payload.timestamp_ms);
    const [sunriseH, sunsetH] = calcSunHours(d, cfg.latitude, cfg.longitude);
    const hour = d.getUTCHours() + d.getUTCMinutes() / 60;
    let dim;
    const dawnStart = sunriseH - 0.5; const dawnEnd = sunriseH + 0.5;
    const duskStart = sunsetH - 0.5; const duskEnd = sunsetH + 0.5;
    if (hour < dawnStart || hour >= duskEnd) dim = 100;
    else if (hour < dawnEnd) dim = 100 * (1 - (hour - dawnStart) / (dawnEnd - dawnStart));
    else if (hour < duskStart) dim = 0;
    else if (hour < duskEnd) dim = 100 * ((hour - duskStart) / (duskEnd - duskStart));
    else dim = 0;
    dim = Math.max(0, Math.min(100, dim + uniform(rng, -3, 3)));
    if (activeEvent && activeEvent.active && activeEvent.zone_id === payload.zone_id) {
        const sev = activeEvent.severity_num || 1;
        if (sev >= 3) dim += 50;
        else if (sev >= 2) dim += 30;
        dim = Math.min(100, dim);
    }
    return {
        site_id: payload.site_id || '',
        city_id: payload.city_id || 'city-berlin',
        zone_id: payload.zone_id || 'zone-001',
        light_id: payload.entity_id,
        timestamp: payload.timestamp,
        dimming_level_pct: dim,
        power_w: (dim / 100) * cfg.rated_power_w
    };
}

// --- Traffic ---
function traffic(payload) {
    const d = new Date(payload.timestamp);
    const rng = makeRng(payload.base_seed, payload.entity_id, 'traffic', payload.timestamp_ms);
    const hour = d.getUTCHours() + d.getUTCMinutes() / 60;
    const we = isWeekendDate(d);
    let i;
    if (hour < 5) i = 10;
    else if (hour < 7) i = 10 + 55 * ((hour - 5) / 2);
    else if (hour < 9) { const pf = 1 - Math.abs(hour - 8); i = 65 + 20 * pf; }
    else if (hour < 10) i = 65 - 25 * (hour - 9);
    else if (hour < 16) i = 40;
    else if (hour < 17) i = 40 + 30 * (hour - 16);
    else if (hour < 19) { const pf = 1 - Math.abs(hour - 18); i = 70 + 15 * pf; }
    else if (hour < 21) i = 70 - 40 * ((hour - 19) / 2);
    else if (hour < 23) i = 30 - 15 * ((hour - 21) / 2);
    else i = 10;
    if (we) i *= 0.7;
    i = Math.max(0, Math.min(100, i + uniform(rng, -8, 8)));
    return {
        city_id: payload.city_id || 'city-berlin',
        zone_id: payload.zone_id || 'zone-001',
        timestamp: payload.timestamp,
        traffic_index: i
    };
}

// --- Visibility ---
function visibility(payload) {
    const cfg = Object.assign({ latitude: 52.52, longitude: 13.405 }, payload.config || {});
    const d = new Date(payload.timestamp);
    const rng = makeRng(payload.base_seed, payload.entity_id, 'visibility', payload.timestamp_ms);
    const hour = d.getUTCHours() + d.getUTCMinutes() / 60;
    let fog;
    if (hour >= 4 && hour < 8) fog = 50 * Math.max(0, 1 - Math.abs(hour - 6) / 2);
    else if (hour >= 8 && hour < 14) fog = Math.max(0, 25 * (1 - (hour - 8) / 6));
    else if (hour >= 20) fog = 15 * ((hour - 20) / 4);
    else if (hour < 4) fog = 20;
    else fog = 5;
    fog = Math.max(0, Math.min(100, fog + uniform(rng, -10, 10)));
    const [sunriseH, sunsetH] = calcSunHours(d, cfg.latitude, cfg.longitude);
    function fmt(h) {
        const hh = Math.floor(h);
        const mm = Math.floor((h - hh) * 60);
        return String(hh).padStart(2, '0') + ':' + String(mm).padStart(2, '0');
    }
    return {
        city_id: payload.city_id || 'city-berlin',
        timestamp: payload.timestamp,
        fog_index: fog,
        visibility: fog < 30 ? 'GOOD' : fog < 60 ? 'MEDIUM' : 'POOR',
        sunrise_time: fmt(sunriseH),
        sunset_time: fmt(sunsetH)
    };
}

// --- Default entity registry (mirrors config/default.yaml shape) ---
const DEFAULT_REGISTRY = {
    site_id: 'site-berlin-001',
    city_id: 'city-berlin',
    weather: [{ entity_id: 'weather-berlin' }],
    pv: [
        { entity_id: 'pv-system-001', config: { nominal_capacity_kwp: 10, system_losses_percent: 15 } },
        { entity_id: 'pv-system-002', config: { nominal_capacity_kwp: 5, system_losses_percent: 12 } }
    ],
    meters: [
        { entity_id: 'janitza-umg96rm-001', config: { base_power_kw: 10, peak_power_kw: 25 } },
        { entity_id: 'janitza-umg96rm-002', config: { base_power_kw: 5, peak_power_kw: 15, initial_energy_kwh: 1000 } }
    ],
    price: [{ entity_id: 'epex-spot-de' }],
    consumers: [
        { entity_id: 'industrial-oven-001', config: { device_type: 'industrial_oven', rated_power_kw: 3, duty_cycle_pct: 70 } },
        { entity_id: 'hvac-001', config: { device_type: 'hvac', rated_power_kw: 2, duty_cycle_pct: 60, operate_on_weekends: true } }
    ],
    streetlights: [
        { entity_id: 'light-z1-001', zone_id: 'zone-001' },
        { entity_id: 'light-z1-002', zone_id: 'zone-001' }
    ],
    traffic: [{ entity_id: 'traffic-z1', zone_id: 'zone-001' }],
    events: [{ entity_id: 'events-z1', zone_id: 'zone-001' }],
    visibility: [{ entity_id: 'visibility-berlin' }]
};

const tick = msg.payload || {};
if (!tick.timestamp || typeof tick.timestamp_ms !== 'number') {
    node.warn('feeds: ignoring invalid tick payload');
    return null;
}

const registry = flow.get('entity_registry') || DEFAULT_REGISTRY;
const baseCtx = {
    base_seed: tick.base_seed,
    timestamp: tick.timestamp,
    timestamp_ms: tick.timestamp_ms,
    site_id: registry.site_id,
    city_id: registry.city_id,
    mode: tick.mode || 'normal'
};

const weatherReading = weather({ ...baseCtx, ...registry.weather[0] });
const pvReadings = registry.pv.map((spec) => pv({ ...baseCtx, ...spec }, weatherReading));
const meterReadings = registry.meters.map((spec) => meter({ ...baseCtx, ...spec }));
const priceReading = price({ ...baseCtx, ...registry.price[0] });
const consumerReadings = registry.consumers.map((spec) => consumer({ ...baseCtx, ...spec }));
const trafficReadings = registry.traffic.map((spec) => traffic({ ...baseCtx, ...spec }));
const eventReadings = registry.events.map((spec) => cityEvent({ ...baseCtx, ...spec }));
const visibilityReadings = registry.visibility.map((spec) => visibility({ ...baseCtx, ...spec }));
// Streetlights honour the zone's active event
const lightReadings = registry.streetlights.map((spec) => {
    const evt = eventReadings.find((e) => e.zone_id === spec.zone_id) || null;
    return streetlight({ ...baseCtx, ...spec }, evt);
});

const totalActiveW = meterReadings.reduce(
    (acc, m) => acc + m.readings.active_power_l1_w + m.readings.active_power_l2_w + m.readings.active_power_l3_w,
    0
);
const totalPvKw = pvReadings.reduce((acc, p) => acc + p.readings.power_output_kw, 0);
const totalConsumerKw = consumerReadings.reduce((acc, c) => acc + c.device_power_kw, 0);

const envelope = {
    type: 'sim.tick',
    schema_version: '1.0',
    timestamp: tick.timestamp,
    mode: tick.mode || 'normal',
    seed: tick.base_seed,
    site_id: registry.site_id,
    smart_energy: {
        meters: meterReadings,
        pv: pvReadings,
        weather: weatherReading,
        price: priceReading,
        consumers: consumerReadings,
        metrics: {
            total_active_power_w: totalActiveW,
            total_pv_power_kw: totalPvKw,
            total_consumer_power_kw: totalConsumerKw,
            net_load_kw: totalActiveW / 1000 + totalConsumerKw - totalPvKw
        }
    },
    smart_city: {
        city_id: registry.city_id,
        timestamp: tick.timestamp,
        events: eventReadings,
        streetlights: lightReadings,
        traffic: trafficReadings,
        visibility: visibilityReadings[0] || null
    }
};

// Cache the latest envelope and per-feed snapshots for REST snapshot APIs.
flow.set('latest_envelope', envelope);
flow.set('latest_meters', meterReadings);
flow.set('latest_pv', pvReadings);
flow.set('latest_weather', weatherReading);
flow.set('latest_price', priceReading);
flow.set('latest_consumers', consumerReadings);

msg.payload = envelope;
return msg;
